1	// Edge function: submit-video (US-045)
2	//
3	// Contract:
4	//   POST { application_id: string,
5	//          video_url: string,
6	//          post_condition_affirmations: { [condition_id: string]: boolean } }
7	//     → 200 { submission_id: string, platform: 'tiktok'|'instagram' }
8	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
9	//     → 401 { error: 'UNAUTHORIZED' }
10	//     → 403 { error: 'FORBIDDEN' }                       // non-creator role
11	//     → 403 { error: 'APPLICATION_NOT_APPROVED' }
12	//     → 404 { error: 'APPLICATION_NOT_FOUND' }
13	//     → 409 { error: 'SUBMISSION_EXISTS' }
14	//     → 422 { error: 'INVALID_VIDEO_URL' }
15	//     → 422 { error: 'INCOMPLETE_AFFIRMATIONS',
16	//             missing_condition_ids: string[] }
17	//     → 502 { error: 'OEMBED_UNAVAILABLE' }               // TikTok upstream
18	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
19	//
20	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Deployed with
21	//       verify_jwt=false at the gateway because the gateway only knows
22	//       about Supabase's own JWT secret — the handler enforces auth.
23	//
24	// Request shape — the US-045 story AC specifies `{ application_id,
25	// video_url, post_condition_affirmations }`. The tech-architecture spec
26	// §5.7 names a future-compatible `{ videos: [...] }` array shape; per
27	// the Ralph convention when story AC and spec disagree at the field
28	// level the story AC wins. The DB layer models multi-video via
29	// `submission_videos.sort_order` so expanding to an array later is a
30	// non-breaking change to this endpoint.
31	//
32	// URL validation (docs/tech-architecture.md §3h):
33	//   - TikTok canonical + shortlinks accepted; canonical gives us the
34	//     numeric `external_id`.
35	//   - TikTok oEmbed endpoint is called to prove the URL points at a
36	//     real, currently-resolvable post. A 404 from TikTok → 422
37	//     INVALID_VIDEO_URL. Network/5xx failures from TikTok → 500.
38	//   - Instagram URLs are validated by regex-shape only because IG
39	//     oEmbed requires an app-level Meta token that we do not currently
40	//     have provisioned. See `_shared/oembed.ts` header.
41	//
42	// Affirmation gate — the spec treats POST conditions (e.g.
43	// "must_mention", "family_friendly") as creator attestations at
44	// submit-time rather than machine-checkable facts. Every `post`-kind
45	// condition on the application's pinned listing_version_id must appear
46	// in `post_condition_affirmations` with a literal `true` value. Missing
47	// or `false` entries → 422 INCOMPLETE_AFFIRMATIONS with the offending
48	// ids so the client can re-surface them.
49	//
50	// Concurrency — the RPC acquires a row lock on the application
51	// (FOR UPDATE) so a duplicate submit interleaving with this one is
52	// serialised and the second request receives SUBMISSION_EXISTS. The
53	// partial unique index `submissions_open_uniq` is the DB backstop.
54	
55	import { createClient } from "npm:@supabase/supabase-js@2";
56	import { verifyJwt } from "../_shared/jwt.ts";
57	import { corsHeaders } from "../_shared/cors.ts";
58	import {
59	  classifyVideoUrl,
60	  fetchTikTokOembed,
61	  type OembedResult,
62	} from "../_shared/oembed.ts";
63	
64	const UUID_RE =
65	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
66	
67	// Guard against a malicious client pasting a megabyte of URL. TikTok /
68	// Instagram share URLs cap well under 300 chars in the wild; 2048 is
69	// the de facto browser URL ceiling.
70	const VIDEO_URL_MAX_LEN = 2048;
71	
72	interface SubmitVideoRequest {
73	  application_id?: unknown;
74	  video_url?: unknown;
75	  post_condition_affirmations?: unknown;
76	}
77	
78	function jsonResponse(status: number, body: unknown): Response {
79	  return new Response(JSON.stringify(body), {
80	    status,
81	    headers: { ...corsHeaders, "Content-Type": "application/json" },
82	  });
83	}
84	
85	function bearerToken(req: Request): string | null {
86	  const raw = req.headers.get("Authorization") ??
87	    req.headers.get("authorization");
88	  if (!raw) return null;
89	  const m = raw.match(/^Bearer\s+(.+)$/i);
90	  return m ? m[1].trim() : null;
91	}
92	
93	function parseAffirmations(
94	  raw: unknown,
95	): Record<string, boolean> | null {
96	  if (raw === null || typeof raw !== "object" || Array.isArray(raw)) {
97	    return null;
98	  }
99	  const out: Record<string, boolean> = {};
100	  for (const [key, value] of Object.entries(raw as Record<string, unknown>)) {
101	    if (typeof value !== "boolean") return null;
102	    out[key] = value;
103	  }
104	  return out;
105	}
106	
107	Deno.serve(async (req) => {
108	  if (req.method === "OPTIONS") {
109	    return new Response(null, { status: 204, headers: corsHeaders });
110	  }
111	  if (req.method !== "POST") {
112	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
113	  }
114	
115	  const token = bearerToken(req);
116	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
117	
118	  let claims;
119	  try {
120	    claims = await verifyJwt(token);
121	  } catch {
122	    return jsonResponse(401, { error: "UNAUTHORIZED" });
123	  }
124	  if (claims.app_role !== "creator") {
125	    return jsonResponse(403, { error: "FORBIDDEN" });
126	  }
127	
128	  let body: SubmitVideoRequest;
129	  try {
130	    body = await req.json();
131	  } catch {
132	    return jsonResponse(400, { error: "INVALID_JSON" });
133	  }
134	
135	  const applicationId =
136	    typeof body.application_id === "string" && UUID_RE.test(body.application_id)
137	      ? body.application_id
138	      : null;
139	  if (!applicationId) {
140	    return jsonResponse(400, { error: "INVALID_REQUEST" });
141	  }
142	
143	  if (
144	    typeof body.video_url !== "string" ||
145	    body.video_url.trim().length === 0 ||
146	    body.video_url.length > VIDEO_URL_MAX_LEN
147	  ) {
148	    return jsonResponse(400, { error: "INVALID_REQUEST" });
149	  }
150	  const videoUrl = body.video_url.trim();
151	
152	  const affirmations = parseAffirmations(body.post_condition_affirmations);
153	  if (affirmations === null) {
154	    return jsonResponse(400, { error: "INVALID_REQUEST" });
155	  }
156	
157	  const classification = classifyVideoUrl(videoUrl);
158	  if (!classification) {
159	    return jsonResponse(422, { error: "INVALID_VIDEO_URL" });
160	  }
161	
162	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
163	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
164	  if (!supabaseUrl || !serviceRoleKey) {
165	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
166	  }
167	
168	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
169	    auth: { persistSession: false, autoRefreshToken: false },
170	  });
171	
172	  const { data: application, error: appError } = await supabase
173	    .from("applications")
174	    .select("id,creator_id,status,listing_version_id")
175	    .eq("id", applicationId)
176	    .maybeSingle();
177	
178	  if (appError) {
179	    console.error("applications lookup failed", appError);
180	    return jsonResponse(500, { error: "DB_ERROR" });
181	  }
182	  if (!application || application.creator_id !== claims.sub) {
183	    return jsonResponse(404, { error: "APPLICATION_NOT_FOUND" });
184	  }
185	  if (application.status !== "approved") {
186	    return jsonResponse(403, { error: "APPLICATION_NOT_APPROVED" });
187	  }
188	  // The applications.listing_version_id column is NOT NULL, but we guard
189	  // explicitly so a future mis-migrated row doesn't silently skip the
190	  // post-condition gate below — an empty `listing_conditions` fetch
191	  // would otherwise flow through with no affirmations required.
192	  if (!application.listing_version_id) {
193	    console.error("application missing listing_version_id", applicationId);
194	    return jsonResponse(500, { error: "DB_ERROR" });
195	  }
196	
197	  const { data: postConditions, error: condError } = await supabase
198	    .from("listing_conditions")
199	    .select("id")
200	    .eq("listing_version_id", application.listing_version_id)
201	    .eq("kind", "post");
202	
203	  if (condError) {
204	    console.error("listing_conditions lookup failed", condError);
205	    return jsonResponse(500, { error: "DB_ERROR" });
206	  }
207	
208	  const missing: string[] = [];
209	  for (const row of postConditions ?? []) {
210	    if (affirmations[row.id] !== true) missing.push(row.id);
211	  }
212	  if (missing.length > 0) {
213	    return jsonResponse(422, {
214	      error: "INCOMPLETE_AFFIRMATIONS",
215	      missing_condition_ids: missing,
216	    });
217	  }
218	
219	  // oEmbed lives after the cheap checks — a TikTok network call on a
220	  // request that would 404/403/422 anyway is pure waste and exposes
221	  // rate-limit surface to unauthenticated noise.
222	  let oembed: OembedResult | null = null;
223	  if (classification.platform === "tiktok") {
224	    try {
225	      oembed = await fetchTikTokOembed(videoUrl);
226	    } catch (err) {
227	      // 502 (not 500) because the failure is upstream — TikTok oEmbed
228	      // is unreachable or returning 5xx. Distinguishing this from
229	      // DB_ERROR lets the client tell retryable-upstream-outage apart
230	      // from a bug in our own database path.
231	      console.error("TikTok oEmbed fetch error", err);
232	      return jsonResponse(502, { error: "OEMBED_UNAVAILABLE" });
233	    }
234	    if (!oembed) {
235	      return jsonResponse(422, { error: "INVALID_VIDEO_URL" });
236	    }
237	  }
238	
239	  const { data: rpcData, error: rpcError } = await supabase.rpc(
240	    "submit_video_rpc",
241	    {
242	      p_application_id: applicationId,
243	      p_creator_id: claims.sub,
244	      p_video_url: videoUrl,
245	      p_platform: classification.platform,
246	      p_external_id: classification.externalId,
247	      p_oembed: oembed ? oembed.raw : null,
248	    },
249	  );
250	
251	  if (rpcError) {
252	    console.error("submit_video_rpc error", rpcError);
253	    return jsonResponse(500, { error: "DB_ERROR" });
254	  }
255	
256	  const result = rpcData as
257	    | { submission_id?: string; error?: string }
258	    | null;
259	
260	  // TOCTOU note: the TS-side status check at line ~184 runs before the
261	  // RPC re-checks under FOR UPDATE. If the lister flips the application
262	  // from `approved` → something else between the two reads, the RPC
263	  // catches it here. The reverse (pending → approved mid-request) is
264	  // caught earlier by the TS check and short-circuits to 403, which is
265	  // accepted as a narrow user-visible glitch — removing the early check
266	  // would require an extra round-trip to surface clean non-approved
267	  // errors on the 99% path. Matches the apply-to-listing pattern.
268	  if (result?.error === "APPLICATION_NOT_FOUND") {
269	    return jsonResponse(404, { error: "APPLICATION_NOT_FOUND" });
270	  }
271	  if (result?.error === "APPLICATION_NOT_APPROVED") {
272	    return jsonResponse(403, { error: "APPLICATION_NOT_APPROVED" });
273	  }
274	  if (result?.error === "SUBMISSION_EXISTS") {
275	    return jsonResponse(409, { error: "SUBMISSION_EXISTS" });
276	  }
277	
278	  if (!result?.submission_id) {
279	    console.error("submit_video_rpc returned unexpected shape", result);
280	    return jsonResponse(500, { error: "DB_ERROR" });
281	  }
282	
283	  return jsonResponse(200, {
284	    submission_id: result.submission_id,
285	    platform: classification.platform,
286	  });
287	});
